function twoSum(nums, target) {
  // 创建哈希表存储数值和索引
  const numMap = new Map();

  for (let i = 0; i < nums.length; i++) {
    const complement = target - nums[i];

    // 检查哈希表中是否存在目标值
    if (numMap.has(complement)) {
      return [numMap.get(complement), i];
    }

    // 将当前数值和索引存入哈希表
    numMap.set(nums[i], i);
  }

  // 如果没有找到，返回空数组
  return [];
}

// 测试用例
console.log(twoSum([2, 7, 11, 15], 9)); // [0, 1]
console.log(twoSum([3, 2, 4], 6)); // [1, 2]
console.log(twoSum([3, 3], 6)); // [0, 1]

// 优化版本：支持返回所有可能的组合
function twoSumAll(nums, target) {
  const numMap = new Map();
  const results = [];

  for (let i = 0; i < nums.length; i++) {
    const complement = target - nums[i];

    if (numMap.has(complement)) {
      results.push([numMap.get(complement), i]);
    }

    numMap.set(nums[i], i);
  }

  return results;
}

class ListNode {
  constructor(val) {
    this.val = val;
    this.next = null;
  }
}

function hasCycle(head) {
  if (!head || !head.next) {
    return false;
  }

  let slow = head;
  let fast = head.next;

  while (slow !== fast) {
    if (!fast || !fast.next) {
      return false; // 快指针到达末尾
    }

    slow = slow.next; // 慢指针移动一步
    fast = fast.next.next; // 快指针移动两步
  }

  return true; // 快慢指针相遇，有环
}

// 测试用例
const node1 = new ListNode(1);
const node2 = new ListNode(2);
const node3 = new ListNode(3);
const node4 = new ListNode(4);

node1.next = node2;
node2.next = node3;
node3.next = node4;
console.log(hasCycle(node1)); // false

// 创建环
node4.next = node2;
console.log(hasCycle(node1)); // true

// 优化版本：返回环的起始节点
function detectCycle(head) {
  if (!head || !head.next) {
    return null;
  }

  let slow = head;
  let fast = head;

  // 检测是否有环
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;

    if (slow === fast) {
      break;
    }
  }

  if (!fast || !fast.next) {
    return null; // 无环
  }

  // 找到环的起始节点
  slow = head;
  while (slow !== fast) {
    slow = slow.next;
    fast = fast.next;
  }

  return slow;
}

